# ----------------- VC MUSIC CLASS -----------------
class VCMusicPlayer:
    def __init__(self, client):
        self.client = client
        self.call = PyTgCalls(client)
        self.started = False

        self.queue = []
        self.loop = False
        self.current = None
        self.play_task = None

    async def start(self):
        if not self.started:
            await self.call.start()
            self.started = True

    # вФАвФАвФАвФАвФА EXTRACT AUDIO (NO DOWNLOAD) вФАвФАвФАвФАвФА
    async def extract_audio(self, query):
        ydl_opts = {
            "format": "bestaudio/best",
            "quiet": True,
            "no_warnings": True,
            "noplaylist": True,
        }

        try:
            with yt_dlp.YoutubeDL(ydl_opts) as ydl:
                if query.startswith(("http://", "https://")):
                    info = ydl.extract_info(query, download=False)
                else:
                    results = ydl.extract_info(f"ytsearch:{query}", download=False)
                    info = results["entries"][0]

                return (
                    info.get("url"),
                    info.get("title", "Unknown"),
                    info.get("duration", 0),
                    info.get("thumbnail"),
                )
        except:
            return None, None, None, None

    # вФАвФАвФАвФАвФА EXTRACT VIDEO (NO DOWNLOAD) вФАвФАвФАвФАвФА
    async def extract_video(self, query):
        ydl_opts = {
            "format": "best[height<=720]/best",
            "quiet": True,
            "no_warnings": True,
            "noplaylist": True,
        }

        try:
            with yt_dlp.YoutubeDL(ydl_opts) as ydl:
                if query.startswith(("http://", "https://")):
                    info = ydl.extract_info(query, download=False)
                else:
                    results = ydl.extract_info(f"ytsearch:{query}", download=False)
                    info = results["entries"][0]

                return (
                    info.get("url"),
                    info.get("title", "Unknown"),
                    info.get("duration", 0),
                    info.get("thumbnail"),
                )
        except:
            return None, None, None, None

    # вФАвФАвФАвФАвФА PLAY FUNCTION (AUDIO OR VIDEO) вФАвФАвФАвФАвФА
    async def play_song(self, chat_id, url, title, duration, thumb, is_video=False):

        if is_video:
            media = MediaStream(
                url,
                audio_parameters=AudioQuality.STUDIO,
                video_parameters=VideoQuality.HD_720p,
            )
        else:
            media = MediaStream(
                url,
                audio_parameters=AudioQuality.STUDIO,
            )

        await self.call.play(chat_id, media)

        self.current = (url, title, duration, thumb, is_video)
                              
        caption = f"""
```вХ≠вФБвФБвФБвФБвЯђ вЮ≤ Started Streaming вЯ≠вФБвФБвФБвФБвХЃ
вФГ
вФГвЯ°вЮ£ Title : {title}
вФГвЯ°вЮ£ Duration : {duration}
вФГвЯ°вЮ£ Loop : {'ON' if self.loop else 'OFF'}
вФГвЯ°вЮ£ Queue : {len(self.queue)} songs
вХ∞вФБвФБвФБвФБвФБвФБвФБвФБвФБвФБвФБвФБвФБвФБвФБвФБвФБвФБвФБвФБвФБвФБвФБвФБвФБвХѓ```
"""

        if thumb:
            try:
                await self.client.send_file(chat_id, thumb, caption=caption)
            except:
                await self.client.send_message(chat_id, caption)
        else:
            await self.client.send_message(chat_id, caption)

        if self.play_task:
            self.play_task.cancel()

        if duration:
            self.play_task = asyncio.create_task(
                self.auto_next(chat_id, duration)
            )

    async def auto_next(self, chat_id, duration):
        await asyncio.sleep(duration)

        if self.loop and self.current:
            await self.play_song(chat_id, *self.current)
            return

        if not self.queue:
            await self.call.leave(chat_id)
            self.current = None
            return

        next_song = self.queue.pop(0)
        await self.play_song(chat_id, *next_song)


