@client.on(events.NewMessage(pattern=r"\.2webp$"))
@owner_only
async def to_webp_cmd(event):
    """Convert image to WebP (Sticker format)"""
    if not event.reply_to_msg_id:
        await client.send_message(event.chat_id, "вЭМ Reply to an image!")
        return
    
    status_msg = await client.send_message(event.chat_id, "рЯФД Converting to WebP...")
    
    file_path, file_name, reply_msg = await download_media(event)
    
    if not file_path:
        await status_msg.edit("вЭМ Could not download file!")
        return
    
    try:
        image = Image.open(file_path)
        webp_path = file_path.rsplit('.', 1)[0] + '.webp'
        
        # Resize for sticker if too large
        max_size = 512
        if image.width > max_size or image.height > max_size:
            image.thumbnail((max_size, max_size), Image.Resampling.LANCZOS)
        
        # Convert RGBA to RGB if needed
        if image.mode == 'RGBA':
            rgb_image = Image.new('RGB', image.size, (255, 255, 255))
            rgb_image.paste(image, mask=image.split()[3])
            image = rgb_image
        
        # Save as WebP
        image.save(webp_path, 'WEBP', quality=80, method=6)
        
        webp_size = get_file_size(webp_path)
        
        await status_msg.edit("вЬЕ WebP created! Uploading...")
        
        # Send as both document and sticker
        await client.send_file(
            event.chat_id,
            webp_path,
            caption=f"рЯОѓ Converted to WebP\nSize: {webp_size:.2f} MB\n\n_Use this as Telegram sticker!_",
            force_document=True
        )
        
        # Also send as sticker
        await client.send_file(
            event.chat_id,
            webp_path,
            force_document=False
        )
        
        await status_msg.delete()
        
    except Exception as e:
        await status_msg.edit(f"вЭМ Conversion failed: {str(e)[:100]}")
    
    finally:
        cleanup_temp_files()

@client.on(events.NewMessage(pattern=r"\.2mp3$"))
@owner_only
async def to_mp3_cmd(event):
    """Convert video to MP3 audio"""
    if not event.reply_to_msg_id:
        await client.send_message(event.chat_id, "вЭМ Reply to a video or audio file!")
        return
    
    status_msg = await client.send_message(event.chat_id, "рЯФД Converting to MP3...")
    
    file_path, file_name, reply_msg = await download_media(event)
    
    if not file_path:
        await status_msg.edit("вЭМ Could not download file!")
        return
    
    try:
        mp3_path = file_path.rsplit('.', 1)[0] + '.mp3'
        
        # Check if ffmpeg is installed
        try:
            subprocess.run(['ffmpeg', '-version'], capture_output=True, check=True)
        except:
            await status_msg.edit("вЭМ FFmpeg not installed!\nInstall: `apt install ffmpeg`")
            return
        
        # Convert to MP3 using ffmpeg
        cmd = [
            'ffmpeg', '-i', file_path,
            '-vn',  # No video
            '-acodec', 'libmp3lame',
            '-ab', '192k',  # Bitrate
            '-ar', '44100',  # Sample rate
            '-y',  # Overwrite
            mp3_path
        ]
        
        process = subprocess.run(cmd, capture_output=True, text=True)
        
        if process.returncode != 0:
            await status_msg.edit(f"вЭМ FFmpeg error: {process.stderr[:200]}")
            return
        
        mp3_size = get_file_size(mp3_path)
        original_size = get_file_size(file_path)
        
        await status_msg.edit("вЬЕ MP3 created! Uploading...")
        
        # Send as audio file
        await client.send_file(
            event.chat_id,
            mp3_path,
            caption=f"рЯОµ Converted to MP3\nOriginal: {original_size:.2f} MB\nMP3: {mp3_size:.2f} MB",
            attributes=[DocumentAttributeFilename('audio.mp3')],
            supports_streaming=True
        )
        
        await status_msg.delete()
        
    except Exception as e:
        await status_msg.edit(f"вЭМ Conversion failed: {str(e)[:100]}")
    
    finally:
        cleanup_temp_files()

@client.on(events.NewMessage(pattern=r"\.2mp4$"))
@owner_only
async def to_mp4_cmd(event):
    """Convert any video format to MP4"""
    if not event.reply_to_msg_id:
        await client.send_message(event.chat_id, "вЭМ Reply to a video!")
        return
    
    status_msg = await client.send_message(event.chat_id, "рЯФД Converting to MP4...")
    
    file_path, file_name, reply_msg = await download_media(event)
    
    if not file_path:
        await status_msg.edit("вЭМ Could not download file!")
        return
    
    try:
        mp4_path = file_path.rsplit('.', 1)[0] + '_converted.mp4'
        
        # Check if already MP4
        if file_path.lower().endswith('.mp4'):
            await status_msg.edit("вЭМ File is already MP4!")
            return
        
        # Check ffmpeg
        try:
            subprocess.run(['ffmpeg', '-version'], capture_output=True, check=True)
        except:
            await status_msg.edit("вЭМ FFmpeg not installed!")
            return
        
        # Convert to MP4
        cmd = [
            'ffmpeg', '-i', file_path,
            '-c:v', 'libx264',  # Video codec
            '-c:a', 'aac',  # Audio codec
            '-movflags', '+faststart',
            '-preset', 'medium',
            '-crf', '23',
            '-y',
            mp4_path
        ]
        
        await status_msg.edit("рЯФД Converting video (this may take time)...")
        
        process = subprocess.run(cmd, capture_output=True, text=True)
        
        if process.returncode != 0:
            await status_msg.edit(f"вЭМ FFmpeg error: {process.stderr[:200]}")
            return
        
        mp4_size = get_file_size(mp4_path)
        
        await status_msg.edit("вЬЕ MP4 created! Uploading...")
        
        await client.send_file(
            event.chat_id,
            mp4_path,
            caption=f"рЯОђ Converted to MP4\nSize: {mp4_size:.2f} MB",
            supports_streaming=True
        )
        
        await status_msg.delete()
        
    except Exception as e:
        await status_msg.edit(f"вЭМ Conversion failed: {str(e)[:100]}")
    
    finally:
        cleanup_temp_files()

@client.on(events.NewMessage(pattern=r"\.2gif$"))
@owner_only
async def to_gif_cmd(event):
    """Convert video to GIF"""
    if not event.reply_to_msg_id:
        await client.send_message(event.chat_id, "вЭМ Reply to a video!")
        return
    
    status_msg = await client.send_message(event.chat_id, "рЯФД Converting to GIF...")
    
    file_path, file_name, reply_msg = await download_media(event)
    
    if not file_path:
        await status_msg.edit("вЭМ Could not download file!")
        return
    
    try:
        gif_path = file_path.rsplit('.', 1)[0] + '.gif'
        
        # Check ffmpeg
        try:
            subprocess.run(['ffmpeg', '-version'], capture_output=True, check=True)
        except:
            await status_msg.edit("вЭМ FFmpeg not installed!")
            return
        
        await status_msg.edit("рЯФД Creating GIF (max 10 seconds)...")
        
        # Convert to GIF (max 10 seconds, 10 fps, 320p)
        cmd = [
            'ffmpeg', '-i', file_path,
            '-t', '10',  # Max 10 seconds
            '-vf', 'fps=10,scale=320:-1:flags=lanczos',
            '-loop', '0',
            '-y',
            gif_path
        ]
        
        process = subprocess.run(cmd, capture_output=True, text=True)
        
        if process.returncode != 0:
            await status_msg.edit(f"вЭМ FFmpeg error: {process.stderr[:200]}")
            return
        
        gif_size = get_file_size(gif_path)
        
        # Check if GIF is too large (>10MB)
        if gif_size > 10:
            await status_msg.edit(f"вЪ†пЄП GIF too large ({gif_size:.2f} MB). Trying smaller size...")
            
            # Try smaller scale
            cmd2 = [
                'ffmpeg', '-i', file_path,
                '-t', '5',  # 5 seconds
                '-vf', 'fps=8,scale=240:-1:flags=lanczos',
                '-loop', '0',
                '-y',
                gif_path
            ]
            subprocess.run(cmd2, capture_output=True)
            gif_size = get_file_size(gif_path)
        
        await status_msg.edit("вЬЕ GIF created! Uploading...")
        
        await client.send_file(
            event.chat_id,
            gif_path,
            caption=f"рЯОЮпЄП Converted to GIF\nSize: {gif_size:.2f} MB"
        )
        
        await status_msg.delete()
        
    except Exception as e:
        await status_msg.edit(f"вЭМ Conversion failed: {str(e)[:100]}")
    
    finally:
        cleanup_temp_files()

@client.on(events.NewMessage(pattern=r"\.compress(?:\s+(\d+))?"))
@owner_only
async def compress_cmd(event):
    """Compress image/video"""
    quality = int(event.pattern_match.group(1)) if event.pattern_match and event.pattern_match.group(1) else 50
    
    if not event.reply_to_msg_id:
        await client.send_message(event.chat_id, "вЭМ Reply to an image or video!\nUsage: .compress [quality 1-100]")
        return
    
    status_msg = await client.send_message(event.chat_id, f"рЯФД Compressing (quality: {quality})...")
    
    file_path, file_name, reply_msg = await download_media(event)
    
    if not file_path:
        await status_msg.edit("вЭМ Could not download file!")
        return
    
    try:
        original_size = get_file_size(file_path)
        
        if reply_msg.photo or (reply_msg.document and 'image' in reply_msg.document.mime_type):
            # Compress image
            compressed_path = file_path.rsplit('.', 1)[0] + '_compressed.jpg'
            
            image = Image.open(file_path)
            
            # Convert RGBA to RGB
            if image.mode in ('RGBA', 'LA', 'P'):
                rgb_image = Image.new('RGB', image.size, (255, 255, 255))
                rgb_image.paste(image, mask=image.split()[-1] if image.mode == 'RGBA' else None)
                image = rgb_image
            
            # Save with compression
            image.save(compressed_path, 'JPEG', quality=quality, optimize=True)
            
            compressed_size = get_file_size(compressed_path)
            reduction = ((original_size - compressed_size) / original_size) * 100
            
            await status_msg.edit("вЬЕ Image compressed! Uploading...")
            await upload_and_send(
                event, 
                compressed_path, 
                f"рЯЧЬпЄП Compressed Image\nOriginal: {original_size:.2f} MB\nCompressed: {compressed_size:.2f} MB\nReduced by: {reduction:.1f}%"
            )
            
        elif reply_msg.video or (reply_msg.document and 'video' in reply_msg.document.mime_type):
            # Compress video
            compressed_path = file_path.rsplit('.', 1)[0] + '_compressed.mp4'
            
            # Check ffmpeg
            try:
                subprocess.run(['ffmpeg', '-version'], capture_output=True, check=True)
            except:
                await status_msg.edit("вЭМ FFmpeg not installed!")
                return
            
            await status_msg.edit("рЯФД Compressing video (this may take time)...")
            
            # Calculate CRF based on quality (inverse: low CRF = high quality)
            crf = int(51 - (quality * 0.51))  # 0-51 scale
            crf = max(18, min(51, crf))  # 18-51 range
            
            cmd = [
                'ffmpeg', '-i', file_path,
                '-c:v', 'libx264',
                '-crf', str(crf),
                '-preset', 'medium',
                '-c:a', 'aac',
                '-b:a', '128k',
                '-movflags', '+faststart',
                '-y',
                compressed_path
            ]
            
            process = subprocess.run(cmd, capture_output=True, text=True)
            
            if process.returncode != 0:
                await status_msg.edit(f"вЭМ FFmpeg error: {process.stderr[:200]}")
                return
            
            compressed_size = get_file_size(compressed_path)
            reduction = ((original_size - compressed_size) / original_size) * 100
            
            await status_msg.edit("вЬЕ Video compressed! Uploading...")
            await client.send_file(
                event.chat_id,
                compressed_path,
                caption=f"рЯЧЬпЄП Compressed Video\nOriginal: {original_size:.2f} MB\nCompressed: {compressed_size:.2f} MB\nReduced by: {reduction:.1f}%",
                supports_streaming=True
            )
        else:
            await status_msg.edit("вЭМ Reply to an image or video!")
            return
        
        await status_msg.delete()
        
    except Exception as e:
        await status_msg.edit(f"вЭМ Compression failed: {str(e)[:100]}")
    
    finally:
        cleanup_temp_files()

@client.on(events.NewMessage(pattern=r"\.mergepdf$"))
@owner_only
async def mergepdf_cmd(event):
    """Merge multiple images into single PDF"""
    if not event.reply_to_msg_id:
        await client.send_message(event.chat_id, "вЭМ Reply to images (album) to merge into PDF!")
        return
    
    status_msg = await client.send_message(event.chat_id, "рЯФД Merging images to PDF...")
    
    try:
        reply_msg = await event.get_reply_message()
        
        image_paths = []
        
        if reply_msg.grouped_id:
            # Album - multiple images
            messages = await client.get_messages(event.chat_id, ids=[reply_msg.id])
            async for msg in client.iter_messages(event.chat_id, offset_id=reply_msg.id, reverse=True):
                if msg.grouped_id == reply_msg.grouped_id:
                    if msg.photo:
                        file_path = os.path.join(TEMP_DIR, f"merge_{msg.id}.jpg")
                        await client.download_media(msg, file=file_path)
                        image_paths.append(file_path)
        else:
            # Single image
            if reply_msg.photo:
                file_path = os.path.join(TEMP_DIR, f"merge_{reply_msg.id}.jpg")
                await client.download_media(reply_msg, file=file_path)
                image_paths.append(file_path)
            else:
                await status_msg.edit("вЭМ Reply to images!")
                return
        
        if not image_paths:
            await status_msg.edit("вЭМ No images found!")
            return
        
        await status_msg.edit(f"рЯФД Processing {len(image_paths)} images...")
        
        # Convert images to PDF
        pdf_path = os.path.join(TEMP_DIR, "merged_output.pdf")
        
        with open(pdf_path, 'wb') as f:
            f.write(img2pdf.convert(image_paths))
        
        pdf_size = get_file_size(pdf_path)
        
        await status_msg.edit("вЬЕ PDF created! Uploading...")
        await upload_and_send(event, pdf_path, f"рЯУЪ Merged PDF\nPages: {len(image_paths)}\nSize: {pdf_size:.2f} MB")
        
        await status_msg.delete()
        
    except Exception as e:
        await status_msg.edit(f"вЭМ Merge failed: {str(e)[:100]}")
    
    finally:
        cleanup_temp_files()

@client.on(events.NewMessage(pattern=r"\.splitpdf(?:\s+(\d+))?"))
@owner_only
async def splitpdf_cmd(event):
    """Split PDF pages"""
    pages_per_file = int(event.pattern_match.group(1)) if event.pattern_match and event.pattern_match.group(1) else 1
    
    if not event.reply_to_msg_id:
        await client.send_message(event.chat_id, "вЭМ Reply to a PDF file!\nUsage: .splitpdf [pages_per_file]")
        return
    
    status_msg = await client.send_message(event.chat_id, f"рЯФД Splitting PDF (every {pages_per_file} page(s))...")
    
    file_path, file_name, reply_msg = await download_media(event)
    
    if not file_path or not file_path.endswith('.pdf'):
        await status_msg.edit("вЭМ Reply to a PDF file!")
        return
    
    try:
        reader = PdfReader(file_path)
        total_pages = len(reader.pages)
        
        await status_msg.edit(f"рЯУД Total pages: {total_pages}\nрЯФД Splitting...")
        
        split_files = []
        
        for i in range(0, total_pages, pages_per_file):
            writer = PdfWriter()
            end = min(i + pages_per_file, total_pages)
            
            for page_num in range(i, end):
                writer.add_page(reader.pages[page_num])
            
            split_path = os.path.join(TEMP_DIR, f"split_part_{i//pages_per_file + 1}.pdf")
            
            with open(split_path, 'wb') as f:
                writer.write(f)
            
            split_files.append(split_path)
        
        await status_msg.edit(f"вЬЕ Split into {len(split_files)} PDFs! Uploading...")
        
        # Upload all split files
        for idx, split_file in enumerate(split_files, 1):
            file_size = get_file_size(split_file)
            await upload_and_send(
                event,
                split_file,
                f"рЯУС Split PDF Part {idx}/{len(split_files)}\nSize: {file_size:.2f} MB"
            )
            await asyncio.sleep(1)
        
        await status_msg.delete()
        
    except Exception as e:
        await status_msg.edit(f"вЭМ Split failed: {str(e)[:100]}")
    
    finally:
        cleanup_temp_files()
        
