@client.on(events.NewMessage(pattern=r"\.quote|\.q(?: (\w+))?"))
@owner_only
async def quote_cmd(event):
    """Create a quote from replied message"""
    if not event.reply_to_msg_id:
        await event.reply("вЭМ Reply to a message to quote it!")
        return
    
    color = event.pattern_match.group(1) if event.pattern_match and event.pattern_match.group(1) else "white"
    
    try:
        reply_msg = await event.get_reply_message()
        sender = await reply_msg.get_sender()
        text = reply_msg.text or reply_msg.raw_text or "Media message"
        
        # Truncate long text
        if len(text) > 500:
            text = text[:500] + "..."
        
        # Create quote format
        quote_text = f"гАМ{text}гАН\n\nвАФ {sender.first_name if sender else 'Unknown'}"
        
        # Color mapping
        colors = {
            "white": "вђЬ",
            "black": "вђЫ",
            "red": "рЯЯ•",
            "blue": "рЯЯ¶",
            "green": "рЯЯ©",
            "yellow": "рЯЯ®",
            "purple": "рЯЯ™",
            "orange": "рЯЯІ",
            "brown": "рЯЯЂ",
        }
        
        color_emoji = colors.get(color.lower(), "вђЬ")
        
        # Send as formatted quote
        await event.reply(f"{color_emoji} **Quote:**\n\n{quote_text}")
        
    except Exception as e:
        await event.reply(f"вЭМ Error creating quote: {e}")

