    await delete_command_message(event)
    if spam_task:
        spam_task.cancel()
        spam_task = None
        stop = await event.reply("рЯЫС Spam stopped.")
        await asyncio.sleep(0.6)
        await stop.delete()
    else:
        no = await event.reply("вЭМ No spam running.")
