@client.on(events.NewMessage(pattern=r'^\.purge(?:\s|$)', func=lambda e: True))
async def purge_handler(event):
    if event.sender_id != OWNER_ID:
        return
    
    if not event.is_reply:
        await event.edit("вЭМ Reply to a message to start purge from there.")
        await asyncio.sleep(0.6)
        await event.delete()
        return
    
    try:
        start_message = await event.get_reply_message()
        start_id = start_message.id
        end_id = event.message.id
        
        await event.delete()  # Delete the purge command message
        
        message_ids = []
        current_id = start_id
        
        while current_id <= end_id:
            message_ids.append(current_id)
            current_id += 1
            # Telegram allows max 100 messages per delete request
            if len(message_ids) >= 100:
                await client.delete_messages(event.chat_id, message_ids)
                message_ids = []
                await asyncio.sleep(0.5)  # Avoid flood
        
        # Delete any remaining messages
        if message_ids:
            await client.delete_messages(event.chat_id, message_ids)
        
        # Send confirmation (it will be the last message)
        confirm_msg = await event.respond(f"вЬЕ Purged {end_id - start_id + 1} messages")
        await asyncio.sleep(3)
        await confirm_msg.delete()
        
    except Exception as e:
        await event.reply(f"вЭМ Error during purge: {str(e)}")
        
import os
import re
import aiohttp
import asyncio
import yt_dlp
from datetime import datetime
from telethon import events

# Required installations:
# pip install yt-dlp aiohttp

@client.on(events.NewMessage(pattern=r"\.dl(?: |$)(.*)"))
async def media_downloader(event):
    """Universal media downloader for Instagram, YouTube, Terabox"""
    if event.sender_id != OWNER_ID:
        return
    
    await delete_command_message(event)
    
    url = event.pattern_match.group(1).strip()
    
    if not url:
        await event.reply("**Usage:** `.dl <url>`\n\n**Supported:**\nвАҐ YouTube\nвАҐ Instagram\nвАҐ Terabox")
        return
    
    # Check URL type
    if "youtube.com" in url or "youtu.be" in url:
        await download_youtube(event, url)
    elif "instagram.com" in url or "instagr.am" in url:
        await download_instagram(event, url)
    elif "terabox" in url or "4funbox" in url or "1024tera" in url:
        await download_terabox(event, url)
    else:
        await event.reply("вЭМ Unsupported URL. Only YouTube, Instagram, and Terabox are supported.")

async def download_youtube(event, url):
    """Download YouTube videos"""
    msg = await event.reply("рЯУ• **Downloading YouTube video...**")
    
    ydl_opts = {
        'format': 'best',
        'outtmpl': 'downloads/%(title)s.%(ext)s',
        'quiet': True,
        'no_warnings': True,
        'extract_flat': False,
        'noplaylist': True,
        'progress_hooks': [lambda d: progress_hook(d, msg)],
    }
    
    try:
        with yt_dlp.YoutubeDL(ydl_opts) as ydl:
            info = ydl.extract_info(url, download=False)
            
            # Get video info
            title = info.get('title', 'Unknown')
            duration = info.get('duration', 0)
            uploader = info.get('uploader', 'Unknown')
            
            # Send info first
            info_msg = f"рЯОђ **YouTube Video**\n"
            info_msg += f"рЯУМ **Title:** {title}\n"
            info_msg += f"вП±пЄП **Duration:** {duration//60}:{duration%60:02d}\n"
            info_msg += f"рЯС§ **Channel:** {uploader}\n"
            info_msg += f"вђЗпЄП **Downloading...**"
            
            await msg.edit(info_msg)
            
            # Download video
            ydl.download([url])
            
            # Find downloaded file
            filename = ydl.prepare_filename(info)
            
            # Check if file exists
            if os.path.exists(filename):
                # Check file size (Telegram limit: 2GB for premium, 2GB for normal)
                file_size = os.path.getsize(filename)
                
                if file_size > 2000 * 1024 * 1024:  # 2GB limit
                    await msg.edit("вЭМ File size exceeds 2GB limit. Trying to download lower quality...")
                    
                    # Try lower quality
                    ydl_opts['format'] = 'best[filesize<2G]'
                    with yt_dlp.YoutubeDL(ydl_opts) as ydl2:
                        ydl2.download([url])
                        filename = ydl2.prepare_filename(info)
                
                # Send video
                await event.client.send_file(
                    event.chat_id,
                    filename,
                    caption=f"рЯОђ **{title}**\n **вЬ® POWERED BY NEXUS USERBOT**\n **рЯМЯ OWNER - @swaha01 & @shdxmr**",
                    supports_streaming=True,
                    progress_callback=lambda current, total: upload_progress(current, total, msg, title)
                )
                
                await msg.delete()
                
                # Clean up
                try:
                    os.remove(filename)
                except:
                    pass
            else:
                await msg.edit("вЭМ Failed to download video.")
                
    except Exception as e:
        await msg.edit(f"вЭМ YouTube Error: {str(e)}")

async def download_instagram(event, url):
    """Download Instagram posts, reels, stories"""
    msg = await event.reply("рЯУЄ **Downloading Instagram media...**")
    
    # Check if it's a story
    is_story = "/stories/" in url
    
    ydl_opts = {
        'outtmpl': 'downloads/%(title)s.%(ext)s',
        'quiet': True,
        'no_warnings': True,
    }
    
    try:
        with yt_dlp.YoutubeDL(ydl_opts) as ydl:
            info = ydl.extract_info(url, download=False)
            
            if 'entries' in info:  # Multiple items (carousel)
                entries = list(info['entries'])
                total = len(entries)
                
                await msg.edit(f"рЯУЄ **Instagram Carousel**\nрЯУК **Posts:** {total}\nвђЗпЄП **Downloading...**")
                
                for i, entry in enumerate(entries, 1):
                    if entry.get('url'):
                        media_url = entry['url']
                        # Download and send each media
                        async with aiohttp.ClientSession() as session:
                            async with session.get(media_url) as resp:
                                if resp.status == 200:
                                    content = await resp.read()
                                    
                                    # Determine file type
                                    content_type = resp.headers.get('Content-Type', '')
                                    ext = '.mp4' if 'video' in content_type else '.jpg'
                                    filename = f"downloads/insta_{i}{ext}"
                                    
                                    with open(filename, 'wb') as f:
                                        f.write(content)
                                    
                                    # Send file
                                    await event.client.send_file(
                                        event.chat_id,
                                        filename,
                                        caption=f"рЯУЄ Instagram Post {i}/{total}",
                                        reply_to=event.message if i == 1 else None
                                    )
                                    
                                    # Clean up
                                    try:
                                        os.remove(filename)
                                    except:
                                        pass
                                    
                                    await asyncio.sleep(1)
                
                await msg.delete()
                
            else:  # Single media
                title = info.get('title', 'Instagram Media')
                uploader = info.get('uploader', 'Unknown')
                
                await msg.edit(f"рЯУЄ **Instagram Post**\nрЯУМ **By:** {uploader}\nвђЗпЄП **Downloading...**")
                
                # Download the media
                ydl.download([url])
                
                # Find downloaded file
                filename = ydl.prepare_filename(info)
                
                if os.path.exists(filename):
                    # Check if it's video or image
                    is_video = filename.endswith(('.mp4', '.mkv', '.webm'))
                    
                    await event.client.send_file(
                        event.chat_id,
                        filename,
                        caption=f"рЯУЄ **Instagram {'Reel' if is_video else 'Post'}\n **вЬ® POWERED BY NEXUS USERBOT**\n **рЯМЯ OWNER - @swaha01 & @shdxmr**",
                        supports_streaming=True if is_video else False,
                        progress_callback=lambda current, total: upload_progress(current, total, msg, title)
                    )
                    
                    await msg.delete()
                    
                    # Clean up
                    try:
                        os.remove(filename)
                    except:
                        pass
                else:
                    await msg.edit("вЭМ Failed to download Instagram media.")
    
    except Exception as e:
        await msg.edit(f"вЭМ Instagram Error: {str(e)}")

async def download_terabox(event, url):
    """Download from Terabox"""
    msg = await event.reply("рЯУ¶ **Processing Terabox link...**")
    
    try:
        # Extract file ID from URL
        pattern = r'terabox\.(?:app|com)/(?:s/|sharing/)?([a-zA-Z0-9_-]+)'
        match = re.search(pattern, url)
        
        if not match:
            await msg.edit("вЭМ Invalid Terabox URL.")
            return
        
        file_id = match.group(1)
        
        # Terabox API endpoint (Note: This might change)
        api_url = f"https://www.terabox.com/api/shorturlinfo?shorturl={file_id}"
        
        headers = {
            'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36',
            'Accept': 'application/json',
        }
        
        async with aiohttp.ClientSession() as session:
            # Get file info
            async with session.get(api_url, headers=headers) as resp:
                if resp.status != 200:
                    await msg.edit("вЭМ Failed to fetch Terabox info.")
                    return
                
                data = await resp.json()
                
                if data.get('errno') != 0:
                    await msg.edit("вЭМ Invalid or expired link.")
                    return
                
                file_info = data.get('list', [{}])[0]
                file_name = file_info.get('server_filename', 'Unknown')
                file_size = file_info.get('size', 0)
                direct_link = file_info.get('dlink', '')
                
                if not direct_link:
                    await msg.edit("вЭМ No download link found.")
                    return
                
                # Convert size to readable format
                size_mb = file_size / (1024 * 1024)
                
                info_msg = f"рЯУ¶ **Terabox File**\n"
                info_msg += f"рЯУД **Name:** {file_name}\n"
                info_msg += f"рЯУК **Size:** {size_mb:.2f} MB\n"
                info_msg += f"вђЗпЄП **Downloading...**"
                
                await msg.edit(info_msg)
                
                # Download file
                download_path = f"downloads/{file_name}"
                
                async with session.get(direct_link, headers=headers) as download_resp:
                    if download_resp.status == 200:
                        total_size = int(download_resp.headers.get('Content-Length', 0))
                        
                        with open(download_path, 'wb') as f:
                            downloaded = 0
                            async for chunk in download_resp.content.iter_chunked(1024*1024):  # 1MB chunks
                                if chunk:
                                    f.write(chunk)
                                    downloaded += len(chunk)
                                    
                                    # Update progress every 5MB
                                    if downloaded % (5*1024*1024) < 1024*1024:
                                        percent = (downloaded / total_size) * 100 if total_size > 0 else 0
                                        await msg.edit(f"{info_msg}\nрЯУ• **Progress:** {percent:.1f}%")
                        
                        # Send file
                        await event.client.send_file(
                            event.chat_id,
                            download_path,
                            caption=f"рЯУ¶ **{file_name}**\nрЯТЊ {size_mb:.2f} MB",
                            progress_callback=lambda current, total: upload_progress(current, total, msg, file_name)
                        )
                        
                        await msg.delete()
                        
                        # Clean up
                        try:
                            os.remove(download_path)
                        except:
                            pass
                    else:
                        await msg.edit("вЭМ Failed to download file.")
    
    except Exception as e:
        await msg.edit(f"вЭМ Terabox Error: {str(e)}")

def progress_hook(d, msg):
    """Progress hook for yt-dlp"""
    if d['status'] == 'downloading':
        percent = d.get('_percent_str', '0%').strip()
        speed = d.get('_speed_str', 'N/A')
        eta = d.get('_eta_str', 'N/A')
        
        asyncio.create_task(
            msg.edit(f"рЯУ• **Downloading...**\nрЯУК **Progress:** {percent}\nрЯЪА **Speed:** {speed}\nвП≥ **ETA:** {eta}")
        )

async def upload_progress(current, total, msg, filename):
    """Upload progress callback"""
    percent = (current / total) * 100 if total > 0 else 0
    
    # Update every 5% progress
    if int(percent) % 5 == 0:
        try:
            await msg.edit(
                f"рЯУ§ **Uploading...**\n"
                f"рЯУД **File:** {filename[:30]}...\n"
                f"рЯУК **Progress:** {percent:.1f}%\n"
                f"рЯТЊ **Size:** {current/(1024*1024):.1f}MB / {total/(1024*1024):.1f}MB"
            )
        except:
            pass
        
@client.on(events.NewMessage(pattern=r'\.delall(?:\s+(.+))?'))
async def delete_all_messages(event):
    """Delete all messages of a user in group"""
    
    if event.sender_id != OWNER_ID:
        return
    
    # Check if in group
    if not event.is_group:
        await event.delete()  # Delete command
        await event.reply("вЭМ This command works only in groups!", reply_to=event.id)
        return
    
    # Check admin permissions
    try:
        participant = await event.client.get_permissions(event.chat_id, event.sender_id)
        if not (participant.is_admin or participant.is_creator):
            await event.delete()  # Delete command
            await event.reply("вЭМ You need to be admin to use this command!", reply_to=event.id)
            return
    except:
        await event.delete()  # Delete command
        await event.reply("вЭМ Could not check admin permissions!", reply_to=event.id)
        return
    
    # Get target user
    target_user = None
    args = event.pattern_match.group(1)
    
    if event.is_reply:
        # Case 1: Reply to user's message
        reply_msg = await event.get_reply_message()
        target_user = reply_msg.sender_id
        
    elif args and args.startswith('@'):
        # Case 2: @username provided
        try:
            username = args[1:]  # Remove @
            user = await event.client.get_entity(username)
            target_user = user.id
        except:
            await event.delete()  # Delete command
            await event.reply(f"вЭМ User @{username} not found!", reply_to=event.id)
            return
    
    elif args and args.isdigit():
        # Case 3: User ID provided
        target_user = int(args)
    
    else:
        await event.delete()  # Delete command
        await event.reply(
            "**Usage:**\n"
            "1. `.delall` - Reply to user's message\n"
            "2. `.delall @username` - Delete messages of @username\n"
            "3. `.delall 123456789` - Delete messages by user ID",
            reply_to=event.id
        )
        return
    
    # Get user info
    try:
        user_entity = await event.client.get_entity(target_user)
        username = f"@{user_entity.username}" if user_entity.username else user_entity.first_name
    except:
        username = f"User {target_user}"
    
    # Delete the command message first
    await event.delete()
    
    # Send initial reply
    response_msg = await event.reply(f"рЯЧСпЄП **Deleting all messages from {username}...**")
    
    deleted_count = 0
    failed_count = 0
    
    try:
        # Get all messages from user
        async for message in event.client.iter_messages(
            event.chat_id,
            from_user=target_user
        ):
            try:
                await message.delete()
                deleted_count += 1
                
                # Delay to avoid flood
                await asyncio.sleep(0.2)
                
            except:
                failed_count += 1
                continue
            
        await response_msg.delete()
        
        # Update final result
        await response_msg.reply(
            f"```вЬЕ Deletion Complete!\n\n"
            f"рЯС§ User: {username}\n"
            f"вЬЕ Deleted: {deleted_count}\n"
            f"вЭМ Failed: {failed_count}```"
        )
        
    except Exception as e:
        await response_msg.edit(f"вЭМ Error: {str(e)[:200]}")
        
