def split_text(text, limit=3900):
    parts = []
    while len(text) > limit:
        cut = text.rfind("\n", 0, limit)
        if cut == -1:
            cut = limit
        parts.append(text[:cut])
        text = text[cut:]
    parts.append(text)
    return parts

@client.on(events.NewMessage(pattern=r"\.name(?: |$)(.*)"))
async def name_handler(event):
    if event.sender_id != OWNER_ID:
        return
    await delete_command_message(event)
    name = event.pattern_match.group(1).strip()

    if not name:
        name = await event.reply("вЭМ Use: `.name YourName`")
        await asyncio.sleep(0.6)
        await name.delete()
        return

    text = "вЬ® **Stylish Name Results** вЬ®\n\n"
    for i, (l, r) in enumerate(STYLES, 1):
        text += f"{i}. `{l} {name} {r}`\n"

    for chunk in split_text(text):
        await event.reply(chunk)

        
