@client.on(events.NewMessage(pattern=r"\.create\s+(.+)"))
async def create_image(event):
    if event.sender_id != OWNER_ID:
        return
    await delete_command_message(event)
    """Photo send karega, file nahi"""
    try:
        prompt = event.pattern_match.group(1).strip()
        
        if not prompt:
            await event.reply("вЭМ Usage: `.create <prompt>`")
            return
        
        msg = await event.reply(f"рЯФД Creating...")
        
        api_url = f"https://text-to-img.apis-bj-devs.workers.dev/?prompt={requests.utils.quote(prompt)}"
        
        async with aiohttp.ClientSession() as session:
            # JSON response lo
            async with session.get(api_url) as resp:
                if resp.status != 200:
                    await msg.edit(f"вЭМ API error: {resp.status}")
                    return
                
                data = await resp.json()
                
                if data.get('status') == 'success' and 'result' in data:
                    # Pehli image URL
                    image_url = data['result'][0]
                    
                    # Image download karo
                    async with session.get(image_url) as img_resp:
                        if img_resp.status != 200:
                            await msg.edit("вЭМ Image download failed")
                            return
                        
                        # IMPORTANT: Temporary file mein save karo
                        import tempfile
                        import os
                        
                        # Temporary file create karo
                        with tempfile.NamedTemporaryFile(suffix='.jpg', delete=False) as tmp:
                            tmp.write(await img_resp.read())
                            tmp_path = tmp.name
                         
                        try:
                            # Photo as photo send karo (yeh important hai)
                            await event.client.send_file(
                                event.chat_id,
                                tmp_path,  # File path
                                caption=f"**Prompt:** `{prompt}`",
                                reply_to=event.reply_to_msg_id if event.is_reply else None,
                                force_document=False  # вЭМ IMPORTANT: file nahi, photo bhejna
                            )
                        finally:
                            # Temporary file delete karo
                            os.unlink(tmp_path)
                        
                        await msg.delete()
                else:
                    await msg.edit(f"вЭМ Error: {data}")
    
    except Exception as e:
        await event.edit(f"вЭМ Error: {str(e)}")


