@client.on(events.NewMessage(pattern=r"\.weather (.+)"))
async def weather_handler(event):
    if event.sender_id != OWNER_ID:
        return
    await delete_command_message(event)
    city = event.pattern_match.group(1)

    url = f"https://api.openweathermap.org/data/2.5/weather?q={city}&appid={API_KEY}&units=metric"
    r = requests.get(url).json()

    if r.get("cod") != 200:
        return await event.reply("City not found sir рЯЪЂ.")

    temp = r["main"]["temp"]
    feels = r["main"]["feels_like"]
    desc = r["weather"][0]["description"]

    await event.reply(
        f"рЯМ§ Weather: {city}\n"
        f"рЯМ° Temp: {temp}¬∞C\n"
        f"рЯ§Т Feels like: {feels}¬∞C\n"
        f"рЯУЭ Condition: {desc}"
    )

# Store old profile photos (file path)
PFP_HISTORY = {}

@client.on(events.NewMessage(pattern=r'^\.cp$', outgoing=True))
async def change_pfp_cmd(event):
    """Change profile picture from replied photo"""
    reply = await event.get_reply_message()
    
    if not reply or not reply.photo:
        await event.edit("вЭМ **Please reply to a photo!**")
        await asyncio.sleep(3)
        await event.delete()
        return
    
    processing = await event.edit("рЯФД **Changing profile picture...**")
    
    try:
        # Download the photo
        with tempfile.NamedTemporaryFile(suffix='.jpg', delete=False) as tmp:
            temp_path = tmp.name
        
        await reply.download_media(file=temp_path)
        
        # Save current PFP path for restore
        current_photos = await client.get_profile_photos('me')
        if current_photos:
            # Download current PFP
            old_pfp_path = f"old_pfp_{event.sender_id}.jpg"
            await client.download_media(current_photos[0], file=old_pfp_path)
            PFP_HISTORY[event.sender_id] = old_pfp_path
        
        # Upload new profile photo
        file = await client.upload_file(temp_path)
        await client(UploadProfilePhotoRequest(file=file))
        
        await processing.edit("вЬЕ **Profile picture changed successfully!**")
        
        # Clean up temp file
        os.unlink(temp_path)
        
    except Exception as e:
        await processing.edit(f"вЭМ **Error:** `{str(e)}`")
    
    await asyncio.sleep(3)
    await event.delete()

@client.on(events.NewMessage(pattern=r'^\.bio(?:\s+(.+))?', outgoing=True))
async def change_bio_cmd(event):
    """Change profile bio"""
    new_bio = event.pattern_match.group(1)
    
    if not new_bio:
        # Show current bio
        me = await client.get_me()
        current_bio = me.about or "No bio set"
        await event.edit(f"рЯУЭ **Current Bio:**\n`{current_bio}`")
        await asyncio.sleep(5)
        await event.delete()
        return
    
    processing = await event.edit("рЯФД **Updating bio...**")
    
    try:
        await client(UpdateProfileRequest(
            about=new_bio
        ))
        
        await processing.edit(f"вЬЕ **Bio updated successfully!**\n\n**New Bio:** `{new_bio}`")
        
    except Exception as e:
        await processing.edit(f"вЭМ **Error:** `{str(e)}`")
    
    await asyncio.sleep(5)
    await event.delete()

@client.on(events.NewMessage(pattern=r'^\.rcp$', outgoing=True))
async def restore_pfp_cmd(event):
    """Restore previous profile picture"""
    
    if event.sender_id not in PFP_HISTORY:
        await event.edit("вЭМ **No previous profile picture found!**")
        await asyncio.sleep(3)
        await event.delete()
        return
    
    processing = await event.edit("рЯФД **Restoring previous profile picture...**")
    
    try:
        old_pfp_path = PFP_HISTORY[event.sender_id]
        
        if not os.path.exists(old_pfp_path):
            await processing.edit("вЭМ **Previous profile picture file not found!**")
            return
        
        # Upload and set old photo
        file = await client.upload_file(old_pfp_path)
        await client(UploadProfilePhotoRequest(file=file))
        
        # Clean up
        os.unlink(old_pfp_path)
        del PFP_HISTORY[event.sender_id]
        
        await processing.edit("вЬЕ **Previous profile picture restored!**")
        
    except Exception as e:
        await processing.edit(f"вЭМ **Error:** `{str(e)}`")
    
    await asyncio.sleep(3)
    await event.delete()
    
