@client.on(events.NewMessage(pattern=r'^\.qr(?: |$)([\s\S]*)$'))
async def qr_generator(event):
    """Generate Colorful QR Code from text/URL"""
    input_text = event.pattern_match.group(1).strip()
    
    if not input_text:
        await event.reply("вЭМ **Usage:** `.qr <text or URL>`\nExample: `.qr https://github.com`")
        return
    
    try:
        # Attractive color combinations
        colors = [
    ("#0F2027", "#203A43"),  # Dark Blue вЖТ Steel Blue (clean & pro)
    ("#141E30", "#243B55"),  # Midnight Blue вЖТ Slate
    ("#232526", "#414345"),  # Charcoal вЖТ Soft Gray (minimal)
    ("#1A2980", "#26D0CE"),  # Deep Blue вЖТ Aqua (balanced)
    ("#2C3E50", "#4CA2AF"),  # Navy вЖТ Muted Cyan
    ("#3A1C71", "#D76D77"),  # Royal Purple вЖТ Soft Rose
    ("#0B486B", "#F56217"),  # Dark Blue вЖТ Orange (high contrast but classy)
    ("#1F4037", "#99F2C8"),  # Forest Green вЖТ Mint
]

        
        fill_color, bg_color = random.choice(colors)
        
        # Generate QR Code
        qr = qrcode.QRCode(
            version=1,
            error_correction=qrcode.constants.ERROR_CORRECT_H,
            box_size=15,
            border=4,
        )
        qr.add_data(input_text)
        qr.make(fit=True)
        
        # Create image with colors
        img = qr.make_image(fill_color=fill_color, back_color=bg_color)
        
        # Convert to RGB
        img = img.convert("RGB")
        
        # Save to bytes as JPG (not PNG)
        buf = io.BytesIO()
        img.save(buf, format='JPEG', quality=95)  # JPEG format with 95% quality
        buf.seek(0)
        buf.name = 'qr_code.jpg'  # JPG filename
        
        # Send as photo
        await event.client.send_message(
            event.chat_id,
            f"**рЯО® QR Code Generated!**",
            file=buf,
            reply_to=event.id,
            parse_mode='md'
        )
        
    except Exception as e:
        await event.reply(f"вЭМ **Error:** {str(e)}")


