# Heart Color Animation
@client.on(events.NewMessage(pattern='.heart'))
async def heart_cmd(event):
    msg = event.message
    
    hearts = [
        "вЭ§пЄП",  # Red Heart
        "рЯІ°",  # Orange Heart
        "рЯТЫ",  # Yellow Heart
        "рЯТЪ",  # Green Heart
        "рЯТЩ",  # Blue Heart
        "рЯТЬ",  # Purple Heart
        "рЯЦ§",  # Black Heart
        "рЯ§Н",  # White Heart
        "рЯ§О",  # Brown Heart
        "рЯТХ",  # Two Hearts
        "рЯТЮ",  # Revolving Hearts
        "рЯТУ",  # Beating Heart
        "рЯТЧ",  # Growing Heart
        "рЯТЦ",  # Sparkling Heart
        "рЯТШ",  # Heart with Arrow
        "рЯТЭ",  # Heart with Ribbon
        "рЯТЯ",  # Heart Decoration
        "вЭ£пЄП",  # Heavy Heart Exclamation
        "рЯТМ",  # Love Letter
        "рЯЂА",  # Anatomical Heart
        "рЯЂґ",  # Heart Hands
    ]
    
    # Show each heart for 0.3 seconds
    for heart in hearts:
        await msg.edit(heart)
        await asyncio.sleep(0.4)
    
    # Final animation - blinking heart
    for i in range(3):
        await msg.edit("рЯТЦ")
        await asyncio.sleep(0.4)
        await msg.edit("вЬ®")
        await asyncio.sleep(0.3)
    
    # End with red heart
    await msg.edit("вЭ§пЄП LOVE YOU! вЭ§пЄП")

# Drugs Animation
