# Rain Animation
@client.on(events.NewMessage(pattern='.rain'))
async def rain_cmd(event):
    msg = event.message
    
    # Cloud forming
    await msg.edit("вШБпЄП")
    await asyncio.sleep(0.3)
    
    await msg.edit("вШБпЄП вШБпЄП")
    await asyncio.sleep(0.3)
    
    await msg.edit("вШБпЄП вШБпЄП вШБпЄП")
    await asyncio.sleep(0.3)
    
    await msg.edit("рЯМІпЄП CLOUDS FORMING...")
    await asyncio.sleep(0.3)
    
    # Rain starts
    rain_frames = [
        """рЯМІпЄП  RAIN  рЯМІпЄП
  '  '  '  '
 '  '  '  ' 
'  '  '  '  """,
        """рЯМІпЄП  RAIN  рЯМІпЄП
 '  '  '  ' 
'  '  '  '  
  '  '  '  '""",
        """рЯМІпЄП  RAIN  рЯМІпЄП
'  '  '  '  
  '  '  '  '
 '  '  '  ' """
    ]
    
    for _ in range(8):
        for frame in rain_frames:
            await msg.edit(frame)
            await asyncio.sleep(0.2)
    
    # Heavy rain
    await msg.edit("""вЫИпЄП HEAVY RAIN вЫИпЄП
рЯТІрЯТІрЯТІрЯТІрЯТІрЯТІрЯТІ
рЯТІрЯТІрЯТІрЯТІрЯТІрЯТІрЯТІ
рЯТІрЯТІрЯТІрЯТІрЯТІрЯТІрЯТІ
рЯТІрЯТІрЯТІрЯТІрЯТІрЯТІрЯТІ
рЯМК PUDDLES FORMING рЯМК""")
    await asyncio.sleep(1)
    
    # Final
    await msg.edit("""рЯМІпЄПрЯМІпЄПрЯМІпЄПрЯМІпЄПрЯМІпЄПрЯМІпЄПрЯМІпЄП
  рЯТІрЯТІрЯТІрЯТІрЯТІрЯТІ
    рЯТІрЯТІрЯТІрЯТІрЯТІ
      рЯТІрЯТІрЯТІрЯТІ
        рЯТІрЯТІрЯТІ
          рЯТІрЯТІ
            рЯТІ
            
вШФ TAKE AN UMBRELLA! вШФ""")

