# ==================== AGAIN RAID FEATURE ====================

again_raid_users = {}

@client.on(events.NewMessage(pattern=r'\.(?:ar|again_raid)(?:\s+(.+))?', outgoing=True))
async def start_again_raid(event):
    if not event.is_reply:
        await event.delete()
        msg = await event.respond("вЭМ Please reply to a user to start again raid!\nUsage: .ar <message>")
        await asyncio.sleep(2)
        await msg.delete()
        return
    
    reply_msg = await event.get_reply_message()
    user_id = reply_msg.sender_id
    raid_message = event.pattern_match.group(1)
    
    if not raid_message:
        await event.delete()
        msg = await event.respond("вЭМ Please provide a message to send!\nUsage: .ar <message>")
        await asyncio.sleep(2)
        await msg.delete()
        return
    
    again_raid_users[user_id] = raid_message
    await event.delete()
    
    try:
        user = await event.client.get_entity(user_id)
        user_name = user.first_name or "User"
        username = f"@{user.username}" if user.username else f"ID: {user_id}"
    except:
        user_name = "User"
        username = f"ID: {user_id}"
    
    msg = await event.respond(f"вЬЕ **Again Raid Started!**\n\n**User:** {user_name}\n**Username:** {username}\n**Auto-Reply:** `{raid_message}`\n\nвЪ†пЄП Har message par automatically reply hoga!\nвЫФ Rokne ke liye: `.sar` ya `.stop_again_raid`")
    await asyncio.sleep(3)
    await msg.delete()

@client.on(events.NewMessage(pattern=r'\.(?:sar|stop_again_raid)(?:\s+(.+))?$', outgoing=True))
async def stop_again_raid(event):
    if event.pattern_match.group(1) == "all":
        if len(again_raid_users) == 0:
            await event.delete()
            msg = await event.respond("вЭМ Koi again raid active nahi hai!")
            await asyncio.sleep(2)
            await msg.delete()
            return
        
        count = len(again_raid_users)
        again_raid_users.clear()
        
        await event.delete()
        msg = await event.respond(f"вЬЕ **Sabhi Again Raids Stopped!**\n\nTotal {count} raids band kar diye gaye.")
        await asyncio.sleep(3)
        await msg.delete()
        return
    
    if not event.is_reply:
        if len(again_raid_users) == 0:
            await event.delete()
            msg = await event.respond("вЭМ Koi again raid active nahi hai!")
            await asyncio.sleep(2)
            await msg.delete()
            return
        
        await event.delete()
        text = "**вЪ†пЄП Active Again Raids:**\n\n"
        for uid, msg_text in again_raid_users.items():
            try:
                user = await event.client.get_entity(uid)
                name = user.first_name or "Unknown"
                text += f"вАҐ **{name}** (ID: `{uid}`) - Reply: `{msg_text[:30]}...`\n"
            except:
                text += f"вАҐ **Unknown User** (ID: `{uid}`) - Reply: `{msg_text[:30]}...`\n"
        
        text += "\n**Stop karne ke liye:**\n"
        text += "вАҐ Kisi user ko reply karke `.sar` - specific user stop\n"
        text += "вАҐ `.sar all` - sabhi raids stop"
        
        msg = await event.respond(text)
        await asyncio.sleep(5)
        await msg.delete()
        return
    
    reply_msg = await event.get_reply_message()
    user_id = reply_msg.sender_id
    await event.delete()
    
    if user_id in again_raid_users:
        del again_raid_users[user_id]
        try:
            user = await event.client.get_entity(user_id)
            user_name = user.first_name or "User"
        except:
            user_name = "User"
        
        msg = await event.respond(f"вЬЕ **Again Raid Stopped!**\n\nUser: {user_name} ke liye again raid band kar diya gaya.")
        await asyncio.sleep(3)
        await msg.delete()
    else:
        msg = await event.respond("вЭМ Ye user again raid mein nahi hai!")
        await asyncio.sleep(2)
        await msg.delete()

@client.on(events.NewMessage(incoming=True))
async def again_raid_handler(event):
    if event.message.out:
        return
    
    me = await event.client.get_me()
    
    if event.sender_id == me.id:
        return
    
    if event.sender_id in again_raid_users:
        raid_message = again_raid_users[event.sender_id]
        await asyncio.sleep(0.1)
        try:
            await event.reply(raid_message)
        except Exception as e:
            logger.error(f"Error in again_raid reply: {e}")
            if event.sender_id in again_raid_users:
                del again_raid_users[event.sender_id]


