import psutil

@client.on(events.NewMessage(pattern=r"^\.(ping|pg)$"))
async def ping_handler(event):
    if not is_owner(event): return
    await delete_command_message(event)
    
    start = time.time()
    msg = await event.reply("рЯПУ Pong!")
    end = time.time()
    response_time = (end - start) * 1000
    
    # Check API latency
    api_start = time.time()
    await client.get_me()
    api_end = time.time()
    api_latency = (api_end - api_start) * 1000
    
    # Calculate uptime
    uptime = datetime.now() - bot_start_time
    days = uptime.days
    hours, remainder = divmod(uptime.seconds, 3600)
    minutes, seconds = divmod(remainder, 60)
    
    uptime_str = ""
    if days > 0:
        uptime_str += str(days) + "d "
    if hours > 0:
        uptime_str += str(hours) + "h "
    if minutes > 0:
        uptime_str += str(minutes) + "m "
    uptime_str += str(seconds) + "s"
    
    # Get system info
    cpu_usage = psutil.cpu_percent()
    memory_usage = psutil.virtual_memory().percent
    
    # Build response text exactly as you want
    response_text = "```рЯПУ Pong!\n"
    
    response_text += "рЯУ° Response Time: " + str(round(response_time, 2)) + "ms\n"
    response_text += "рЯТУ API Latency: " + str(round(api_latency, 2)) + "ms\n"
    response_text += "рЯЦ•пЄП CPU Usage: " + str(cpu_usage) + "%\n"
    response_text += "рЯІ† Memory: " + str(memory_usage) + "%\n"
    response_text += "рЯУК Uptime: " + uptime_str + "```"
    
    await msg.edit(response_text)
    await delete_after_delay(msg)
    
