# FAKE WEB SERVER TO KEEP USERBOT RUNNING
async def handle(request):
    return web.Response(text="Userbot running", status=200)

async def start_web_server():
    app = web.Application()
    app.router.add_get("/", handle)
    port = int(os.environ.get("PORT", 10000))
    runner = web.AppRunner(app)
    await runner.setup()
    site = web.TCPSite(runner, "0.0.0.0", port)
    await site.start()
    print(f"Web server started on port {port}")


# рЯЪА START COMMAND
@client.on(events.NewMessage(pattern=r"^\.(start|stt)$"))
async def start_handler(event):
    if not is_owner(event): return
    await delete_command_message(event)
    start_msg = await event.reply(
    "```рЯ§Ц рЭРФрЭРЛрЭРУрЭРИрЭРМрЭРАрЭРУрЭРД рЭРНрЭРДрЭРЧрЭРФрЭРТ рЭРФрЭРТрЭРДрЭРСрЭРБрЭРОрЭРУ рЭРАрЭРВрЭРУрЭРИрЭРХрЭРАрЭРУрЭРДрЭРГ!\n"
    "вФБвФБвФБвФБвФБвФБвФБвФБвФБвФБвФБвФБвФБвФБвФБвФБ\n"
    "вП∞ рЭРВрЭРФрЭРСрЭРСрЭРДрЭРНрЭРУ рЭРГрЭРДрЭРЛрЭРАрЭРШ: 6 seconds\n"
    "рЯУМ рЭРВрЭРЗрЭРАрЭРНрЭРЖрЭРД рЭРГрЭРДрЭРЛрЭРАрЭРШ: .delay <seconds>\n"
    "рЯФІ рЭРВрЭРОрЭРМрЭРМрЭРАрЭРНрЭРГ рЭРЛрЭРИрЭРТрЭРУ: .help\n"
    "вФБвФБвФБвФБвФБвФБвФБвФБвФБвФБвФБвФБвФБвФБвФБвФБ\n"
    "рЯМЯ Stay tuned for powerful automation!\n\n"
    "(рЭРТрЭР≠рЭРЪрЭР≠рЭРЃрЭРђ: Online | Mode: Smooth)```"
)
    await asyncio.sleep(7)
    await delete_after_delay(start_msg)


# Start the client
async def main():
    global bot_start_time
    bot_start_time = datetime.now()
    
    print(f"рЯЪА Starting {len(clients)} sessions...")
 
    # Sabhi clients ko start karo
    for i, c in enumerate(clients):
        await c.start()
        me = await c.get_me()
        print(f"  вЬЕ Session {i+1} logged in as: {me.first_name} ({me.id})")
 
    # Sabhi sessions pe handlers register karo
    register_all_handlers()
 
    # Web server start karo (sirf ek baar)
    await start_web_server()
 
    print(f"\nвЬЕ All {len(clients)} sessions running! Owner ID: {OWNER_ID}")
    print("Muted list:", muted)
 
    # Sabhi clients ko saath mein run karo
    await asyncio.gather(
        *[c.run_until_disconnected() for c in clients]
    )

if __name__ == "__main__":
    try:
        asyncio.run(main())
    except KeyboardInterrupt:
        print("Stopped by user.")
